use std::collections::HashMap;

struct Record {
    key: String,
    value: String,
}

fn parse_data(input: &str) -> Vec<Record> {
    let mut records = Vec::new();
    let mut current_record: Option<Record> = None;

    for line in input.lines() {
        if line.trim().is_empty() {
            continue;
        }

        match line.split(':').collect::<Vec<&str>>().len() {
            1 => {
                if let Some(record) = current_record { records.push(record); }
                current_record = None;
            }
            2 => {
                let parts: Vec<&str> = line.split(':').collect();
                let key = parts[0].trim().to_string();
                let value = parts[1].trim().to_string();

                if current_record.is_some() {
                    records.push(Record { key: current_record.as_ref().unwrap().key.clone(), value: current_record.as_ref().unwrap().value.clone() });
                }
                current_record = Some(Record { key, value });
            }
            _ => {
                if let Some(record) = current_record { records.push(record); }
                current_record = None;
            }
        }
    }

    if let Some(record) = current_record {
        records.push(record);
    }

    records
}

fn main() {
    let data_stream = "user:Alice: OKnsetting:timeout: 30nmalformed line that will failnnext:item: Value2";
    let parsed = parse_data(data_stream);
    for record in parsed {
        println!("Key: {}", record.key);
    }
