use std::collections::HashMap;
use std::io::{self, Write};

#[derive(Debug)]
struct BuildTarget {
    name: String,
    dependencies: Vec<String>,
}

fn parse_config(input: &str) -> io::Result<Vec<BuildTarget>> {
    let mut targets = Vec::new();
    let lines = input.lines();

    for line in lines {
        let trimmed = line.trim();
        if trimmed.is_empty() || !trimmed.starts_with('[') {
            continue;
        }

        if let Some(start) = trimmed.find('=') {
            let section_name = &trimmed[1..line.len()-1].split_whitespace().next().unwrap_or(&"Unknown");
            let mut target = BuildTarget { name: section_name.to_string(), dependencies: Vec::new() };

            if let Some(dep_line) = line.lines().find(|l| l.contains(":")) {
                let parts: Vec<&str> = dep_line.split(':').collect();
                if parts.len() == 2 {
                    target.dependencies.push(parts[1].trim().to_string());
                }
            }

            targets.push(target);
        }
    }

    Ok(targets)
}

use std::collections::HashMap;
use serde::{Deserialize, Serialize};

#[derive(Debug, Clone, PartialEq, Eq, Hash, Deserialize, Serialize)]
struct Record {
    ip_address: String,
    error_message: String,
}

fn process_log_file(file_path: &str) -> Result<Vec<Record>, std::io::Error> {
    let content = std::fs::read_to_string(file_path)?;
    let mut records = Vec::new();

    for line in content.lines() {
        if line.contains("ERROR") && line.contains(":d+") {
            let parts: Vec<&str> = line.split("|").collect();
            if parts.len() >= 2 {
                let ip_candidate = parts.get(0).map(|s| s.trim()).unwrap_or(&String::from("UNKNOWN")).to_string();
                let error_msg_candidate = parts.last().map(|s| s.trim()).unwrap_or(&String::from("NO_MSG")).to_string();
                if !ip_candidate.is_empty() && !error_msg_candidate.contains(":d+"){
                    records.push(Record {
                        ip_address: ip_candidate,
                        error_message: error_msg_candidate.replace("n", "")
                    });
                }
            }
        }
    }
    Ok(records)
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let file1 = "system_log_1.txt";
    let file2 = "security_audit.log";

    std::fs::write(file1, "INFO: Startup OK|IP:192.168.1.1|MSG:System BootnERROR: Failed to connect|IP:10.0.0.5|MSG:Timeout after 3 attemptsnWARN: Low disk space|IP:192.168.1.1|MSG:Disk usage highnERROR: Authentication failed|IP:172.16.0.2|MSG:Bad password attemptn");
    std::fs::write(file2, "Log entry|IP:203.0.113.9|ERROR: Service Down|Details:nERROR: Kernel panic detected|IP:10.0.0.5|Details:nINFO: Clean shutdown|IP:192.168.1.1|MSG:Normal exitn");

    let logs1 = process_log_file(file1)?;
    println!("Found {} records in {}n", logs1.len(), file1);

    let logs2 = process_log_file(file2)?;
    println!("Found {} records in {}n", logs2.len(), file2);

    let mut unique_ips: HashMap<String, i32> = HashMap::new();
    for record in logs1.into_iter().chain(logs2.into_iter()) {
        unique_ips.entry(record.ip_address).and_modify(|count| *count += 1).or_insert(1);
    }

    println!("n--- Summary ---");
    println!("Total unique IPs found across all logs: {}", unique_ips.len());
    for (ip, count) in unique_ips { 
        println!("IP {} appeared {} times.", ip, count);
    }

    Ok(())
}

use std::collections::HashMap;

struct BoardState {
    pieces: HashMap<String, String>,
}

impl BoardState {
    fn new() -> Self {
        BoardState { pieces: HashMap::new() }
    }

    fn process_move_description(input: &str) -> Option<String> {
        let parts: Vec<&str> = input.split_whitespace().collect();
        if parts.len() < 3 {
            return None;
        }

        let start_pos = parts[0].chars().collect::<String>();
        let end_pos = parts[1].chars().collect::<String>();

        if !start_pos.is_empty() && !end_pos.is_empty() {
            return Some(format!("Processed move from {} to {}", start_pos, end_pos));
        }
        None
    }
}

fn main() {
    let description1 = "e2 e4";
    let description2 = "a7 a6 b8";
    let description3 = "Invalid input";

    if let Some(result) = BoardState::process_move_description(description1) {
        println!("Success 1: {}", result);
    }

    if let Some(result) = BoardState::process_move_description(description2) {
        println!("Success 2: {}", result);
    }

    match BoardState::process_move_description(description3) {
        Some(result) => println!("Unexpected Success 3: {}", result),
        None => println!("Failure 3: Could not parse the move description.")
    }
}

use std::collections::HashMap;
use std::io;

#[derive(Debug)]
pub struct ConfigData {
    pub settings: HashMap<String, String>,
}

fn parse_kv(line: &str) -> Option<(String, String)> {
    let parts: Vec<&str> = line.splitn(2, '=').collect();
    if parts.len() != 2 {
        return None;
    }
    Some((parts[0].to_string(), parts[1].to_string()))
}

fn load_config(data: &str) -> io::Result<ConfigData> {
    let mut settings = HashMap::new();
    let mut current_key: Option<String> = None;

    for line in data.trim().lines() {
        let trimmed_line = line.trim();
        if trimmed_line.is_empty() { continue; }

        if !trimmed_line.starts_with('{') && !trimmed_line.contains(':') { 
            continue;
        }

        if let Some((key, value)) = parse_kv(trimmed_line) {
            settings.insert(key, value);
        }
    }

    Ok(ConfigData { settings })
}
